// ── UTILITAIRES ────────────────────────────────────────
function clearAll() {
  if (!confirm(_t('confirm_clear_text'))) return;
  setDomVal('raw-input', '');
  paginateNodes([], []);
  updateStats();
  updateChapterList([]);
  markUnsaved();
  showToast(_t('toast_text_cleared'));
}

function showToast(msg, duration = 3000, level = 'info') {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.className = '';
  t.classList.add('show');
  if (level === 'error')   t.style.background = '#7f1d1d';
  else if (level === 'ok') t.style.background = '#14532d';
  else                     t.style.background = 'var(--ink)';
  clearTimeout(t._timer);
  t._timer = setTimeout(() => {
    t.classList.remove('show');
    t.style.background = '';
  }, duration);
}

// ── EXPORT PDF — pdfmake (marges mathématiques, sans rendu navigateur) ─────
// Charge pdfmake + vfsfonts depuis CDN si nécessaire, puis génère le PDF.
// Les marges sont passées directement à pdfmake en points — aucune dépendance
// au moteur CSS/print du navigateur.


// ── Rendu image universel (rotation + mode contain/cover) ─────────────────────
// Utilisé par printPDF et exportWord. Retourne un data URL PNG à 150 dpi.
function _getRotatedBB(w, h, angleDeg) {
  const rad = angleDeg * Math.PI / 180;
  const cos = Math.abs(Math.cos(rad)), sin = Math.abs(Math.sin(rad));
  return { bbW: Math.round(w * cos + h * sin), bbH: Math.round(w * sin + h * cos) };
}

async function renderImgToDataURL(src, targetWmm, targetHmm, rotation, mode) {
  const DPI = 150;  // 150 dpi suffit pour pdfmake (qui travaille en points)
  const MM_PX = DPI / 25.4;
  const rot = ((rotation || 0) % 360 + 360) % 360;

  const im = await new Promise((res, rej) => {
    const i = new Image(); i.onload = () => res(i); i.onerror = rej; i.src = src;
  });

  const { bbW: srcLogW, bbH: srcLogH } = _getRotatedBB(im.naturalWidth, im.naturalHeight, rot);
  const tWpx = Math.round(targetWmm * MM_PX);
  const tHpx = Math.round(targetHmm * MM_PX);
  const scaleX = tWpx / srcLogW, scaleY = tHpx / srcLogH;
  const scale  = mode === 'cover' ? Math.max(scaleX, scaleY) : Math.min(scaleX, scaleY);
  const drawW  = im.naturalWidth  * scale;
  const drawH  = im.naturalHeight * scale;

  const canvas = document.createElement('canvas');
  canvas.width = tWpx; canvas.height = tHpx;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, tWpx, tHpx);
  ctx.save();
  ctx.translate(tWpx / 2, tHpx / 2);
  ctx.rotate(rot * Math.PI / 180);
  ctx.drawImage(im, -drawW / 2, -drawH / 2, drawW, drawH);
  ctx.restore();
  return canvas.toDataURL('image/png');
}

function _loadScript(url) {
  return new Promise((resolve, reject) => {
    if (document.querySelector('script[src="' + url + '"]')) { resolve(); return; }
    const s = document.createElement('script');
    s.src = url;
    s.onload  = resolve;
    s.onerror = () => reject(new Error('Impossible de charger ' + url));
    document.head.appendChild(s);
  });
}

async function printPDF() {
  const container = document.getElementById('pages-container');
  if (!container || !container.children.length) {
    showToast(_t('toast_printing_no_text')); return;
  }

  setExportBusy(true);
  showToast('⏳ Génération PDF en cours…', 3000);

  try {
    // ── 1. Charger pdfmake si absent ───────────────────────────────────────
    if (typeof pdfMake === 'undefined') {
      await _loadScript('https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.2.10/pdfmake.min.js');
      await _loadScript('https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.2.10/vfs_fonts.min.js');
    }
    // ── Polices embarquées (woff latin) ─────────────────────────────────────
    pdfMake.vfs = pdfMake.vfs || {};
    Object.assign(pdfMake.vfs, {
      'ss4-regular': '',
      'ss4-italic': '',
      'ss4-bold': '',
      'pf-regular': '',
      'pf-bold': '',
      'pf-italic': ''
    });
    pdfMake.fonts = pdfMake.fonts || {};
    Object.assign(pdfMake.fonts, {
      SourceSerif4: {
        normal:      'ss4-regular',
        bold:        'ss4-bold',
        italics:     'ss4-italic',
        bolditalics: 'ss4-italic',
      },
      PlayfairDisplay: {
        normal:      'pf-regular',
        bold:        'pf-bold',
        italics:     'pf-italic',
        bolditalics: 'pf-italic',
      },
    });


    // ── 2. Dimensions depuis getPageDims() (source unique) ─────────────────
    const dims = getPageDims();
    const MM   = 2.8346; // 1 mm → points PDF

    const pageW   = dims.pageW   * MM;
    const pageH   = dims.pageH   * MM;
    const mTop    = dims.padTop  * MM;
    const mBot    = dims.padBot  * MM;
    const mLeft   = dims.padLeft * MM;
    const mRight  = dims.padRight * MM;

    const isSubmit = (dims.fmt === 'SUBMIT_AMI' || dims.fmt === 'SUBMIT_STD');

    // ── 3. Polices ──────────────────────────────────────────────────────────
    // pdfmake embarque Roboto par défaut. On mappe les styles édition sur elles.
    // Pour un rendu optimal, on utilise les polices intégrées (pas de chargement réseau).
    const bodyFont   = 'SourceSerif4';    // Source Serif 4 — corps du texte
    const titleFont  = 'PlayfairDisplay';  // Playfair Display — titres / chapitres
    const headerFont = 'SourceSerif4';    // Source Serif 4 — texte courant

    const fontSize   = parseFloat(dims.fs)  || 11;
    const lineHeight = parseFloat(dims.lh)  || 1.5;

    // ── 4. Extraire le titre, auteur, sous-titre ────────────────────────────
    const titre     = getDomVal('pg-titre').trim();
    const auteur    = getDomVal('pg-auteur').trim();
    const soustitre = getDomVal('pg-soustitre').trim();
    const genre     = getDomVal('pg-genre').trim();
    const headerCourant = getDomVal('header-courant').trim();
    const folioStart    = parseInt(getDomVal('folio-start') || '1', 10) || 1;

    // ── 5. Parser les pages du DOM → contenu pdfmake ───────────────────────
    // On lit le DOM rendu (qui a déjà paginé et mis en forme) pour en extraire
    // le texte structuré et le convertir en définition pdfmake.

    const content = [];
    let lastWasFullPageImg = false; // évite une page vierge entre image pleine page et chapitre suivant

    // Helper : convertit les nœuds enfants d'un élément en tableau de inline pdfmake
    function domToInlines(el) {
      const inlines = [];
      el.childNodes.forEach(node => {
        if (node.nodeType === Node.TEXT_NODE) {
          const t = node.textContent;
          if (t) inlines.push(t);
        } else if (node.nodeType === Node.ELEMENT_NODE) {
          const tag = node.tagName.toLowerCase();
          const sub = domToInlines(node);
          const cs  = window.getComputedStyle(node);
          const bold   = cs.fontWeight >= 600 || tag === 'b' || tag === 'strong';
          const italic = cs.fontStyle === 'italic' || tag === 'i' || tag === 'em';
          const underline = cs.textDecorationLine.includes('underline') || tag === 'u';
          if (sub.length === 0) return;
          if (bold || italic || underline) {
            inlines.push({ text: sub, bold, italics: italic, decoration: underline ? 'underline' : undefined });
          } else {
            sub.forEach(s => inlines.push(s));
          }
        }
      });
      return inlines;
    }

    // ── 5a. Page de garde ───────────────────────────────────────────────────
    if (titre || auteur) {
      if (genre) {
        content.push({ text: genre.toUpperCase(), font: titleFont, fontSize: 9,
          characterSpacing: 2, color: '#8a827a', alignment: 'center',
          margin: [0, pageH * 0.25, 0, 36] });
      }
      if (titre) {
        content.push({ text: titre, font: 'PlayfairDisplay', fontSize: 28, bold: true,
          alignment: 'center', margin: [0, genre ? 0 : pageH * 0.3 / MM, 0, 12] });
      }
      if (soustitre) {
        content.push({ text: soustitre, font: 'PlayfairDisplay', fontSize: 14, italics: true,
          alignment: 'center', color: '#4a443e', margin: [0, 0, 0, 24] });
      }
      if (auteur) {
        content.push({ text: auteur, font: titleFont, fontSize: 13,
          alignment: 'center', color: '#4a443e', margin: [0, 24, 0, 0] });
      }
      content.push({ text: '', pageBreak: 'after' });
    }

    // ── 5b. Pages de contenu ────────────────────────────────────────────────
    const pages = container.querySelectorAll('.book-page');
    pages.forEach((page, pi) => {
      if (page.dataset.isTitlePage === '1') return; // déjà géré

      // Texte courant (en-tête de page) si présent
      // → géré via header() dans le docDefinition

      // ── Page pleine dédiée à une image (mode middle/fill) ──────────────────
      if (page.dataset.isFullPageImg === '1') {
        const key    = page.dataset.imgKey;
        const imgDat = (typeof images !== 'undefined' && images[key]) ? images[key] : null;
        const imgSrc = imgDat ? imgDat.src : null;
        if (!imgSrc) return;

        // Lire toutes les options depuis le dataset (enregistrées à la construction)
        const valign   = page.dataset.valign   || 'middle';
        const userWpct = parseFloat(page.dataset.userWpct) || 100;
        const align    = page.dataset.align    || 'center';
        const rot      = parseFloat(page.dataset.rotation) || 0;
        const mTmm     = parseFloat(page.dataset.marginTopMm)   || dims.padTop;
        const mBmm     = parseFloat(page.dataset.marginBotMm)   || dims.padBot;
        const mLmm     = parseFloat(page.dataset.marginLeftMm)  || dims.padLeft;
        const mRmm     = parseFloat(page.dataset.marginRightMm) || dims.padRight;

        // Dimensions zone disponible en mm (pour renderImgToDataURL)
        const availWmm = dims.pageW - mLmm - mRmm;
        const availHmm = dims.pageH - mTmm - mBmm;
        const imgWmm   = availWmm * userWpct / 100;

        // Mode de rendu canvas
        const canvasMode = valign === 'fill' ? 'cover' : 'contain';

        // Pour mode 'middle' : on rend à imgWmm × availHmm (canvas contain centrera)
        // Pour mode 'fill'   : on rend à availWmm × availHmm (canvas cover remplira)
        const targetWmm = valign === 'fill' ? availWmm : imgWmm;
        const targetHmm = valign === 'fill' ? availHmm : availHmm;

        // Dimensions en points PDF pour absolutePosition
        const mLPt = mLmm * MM, mTPt = mTmm * MM;
        const availWPt = availWmm * MM, availHPt = availHmm * MM;
        const targetWPt = targetWmm * MM, targetHPt = targetHmm * MM;

        // Position X selon alignement
        let xPos = mLPt + (availWPt - targetWPt) / 2; // center par défaut
        if (align === 'left')  xPos = mLPt;
        if (align === 'right') xPos = mLPt + availWPt - targetWPt;
        const yPos = mTPt; // le canvas gère déjà le centrage vertical via contain

        content.push({
          _imagePromise: renderImgToDataURL(imgSrc, targetWmm, targetHmm, rot, canvasMode),
          _targetWPt: targetWPt,
          _targetHPt: targetHPt,
          _xPos: xPos,
          _yPos: yPos,
          _isFullPageImg: true,
          _needsPageBreakBefore: content.length > 0
        });
        lastWasFullPageImg = true;
        return;
      }

      // Lire les nœuds texte dans frame-body et frame-header
      const fh = page.querySelector('.frame-header');
      const fb = page.querySelector('.frame-body');

      // Titre de chapitre depuis frame-header
      if (fh) {
        const chEl = fh.querySelector('.chapter-heading, h2, h3');
        if (chEl) {
          const chText = chEl.textContent.replace(/✦/g, '').trim();
          if (chText) {
            if (content.length > 0 && !lastWasFullPageImg) {
              content.push({ text: '', pageBreak: 'before' });
            }
            lastWasFullPageImg = false;
            content.push({
              text: chText,
              font: titleFont,
              fontSize: isSubmit ? fontSize : Math.round(fontSize * 1.5),
              bold: !isSubmit,
              italics: !isSubmit,
              alignment: isSubmit ? 'left' : 'center',
              margin: [0, isSubmit ? 24 : dims.chapterHeaderMm * MM * 0.3, 0, isSubmit ? 12 : 24],
              color: '#1a1714'
            });
          }
        }
      }

      // Contenu du frame-body
      if (fb) {
        const children = Array.from(fb.childNodes).filter(n => {
          if (n.nodeType === Node.TEXT_NODE) return n.textContent.trim() !== '';
          if (n.nodeType === Node.ELEMENT_NODE) {
            const cl = n.classList;
            if (cl.contains('folio') || cl.contains('running-header') ||
                cl.contains('page-number-label')) return false;
            return true;
          }
          return false;
        });

        children.forEach(node => {
          if (node.nodeType !== Node.ELEMENT_NODE) return;

          const tag = node.tagName ? node.tagName.toLowerCase() : '';
          const cl  = node.classList;

          // Saut de scène
          if (cl.contains('scene-break') || node.textContent.trim() === '* * *' || node.textContent.trim() === '—') {
            content.push({ text: node.textContent.trim() || '* * *',
              alignment: 'center', margin: [0, 8, 0, 8], color: '#7c5c3a' });
            return;
          }

          // Image inline
          if (cl.contains('book-image') || tag === 'figure') {
            const imgEl = node.querySelector('img');
            if (imgEl && imgEl.src && imgEl.src !== '') {
              try {
                // Convertir l'image en base64 via canvas (supporte blob:, http, data:)
                const imgToBase64 = (imgElement) => new Promise((resolve) => {
                  // Si déjà data URI, retourner directement
                  if (imgElement.src.startsWith('data:')) {
                    resolve(imgElement.src); return;
                  }
                  const canvas = document.createElement('canvas');
                  const natW = imgElement.naturalWidth  || imgElement.width  || 200;
                  const natH = imgElement.naturalHeight || imgElement.height || 200;
                  canvas.width  = natW;
                  canvas.height = natH;
                  const ctx = canvas.getContext('2d');
                  try {
                    ctx.drawImage(imgElement, 0, 0, natW, natH);
                    resolve(canvas.toDataURL('image/png'));
                  } catch(e) {
                    // CORS fallback : charger depuis URL via new Image crossOrigin
                    const img2 = new Image();
                    img2.crossOrigin = 'anonymous';
                    img2.onload = () => {
                      const c2 = document.createElement('canvas');
                      c2.width = img2.naturalWidth || 200;
                      c2.height = img2.naturalHeight || 200;
                      c2.getContext('2d').drawImage(img2, 0, 0);
                      try { resolve(c2.toDataURL('image/png')); }
                      catch(e2) { resolve(null); }
                    };
                    img2.onerror = () => resolve(null);
                    img2.src = imgElement.src;
                  }
                });
                // Collecte asynchrone — on stocke une promesse résolue inline
                const pxW  = imgEl.naturalWidth  || imgEl.width  || 200;
                const pxH  = imgEl.naturalHeight || imgEl.height || 200;
                const maxW = pageW - mLeft - mRight;
                const imgW = Math.min(pxW * 0.75, maxW);
                const align = cl.contains('img-float-right') ? 'right'
                            : cl.contains('img-float-left')  ? 'left' : 'center';
                // Lire spaceBefore/spaceAfter depuis images[] (défauts : 16pt haut, 10pt bas)
                const _imgKey  = node.dataset.imgKey || '';
                const _imgDat  = (typeof images !== 'undefined' && _imgKey && images[_imgKey]) ? images[_imgKey] : {};
                const _pdfMT   = _imgDat.spaceBefore != null ? _imgDat.spaceBefore : 16;
                const _pdfMB   = _imgDat.spaceAfter  != null ? _imgDat.spaceAfter  : 10;
                // Placeholder avec référence à la promesse base64
                const placeholder = { _imagePromise: imgToBase64(imgEl),
                  width: imgW, alignment: align, margin: [0, _pdfMT, 0, _pdfMB] };
                content.push(placeholder);
              } catch(e) {}
            }
            const cap = node.querySelector('.caption');
            if (cap && cap.textContent.trim()) {
              content.push({ text: cap.textContent.trim(),
                fontSize: fontSize * 0.85, italics: true, alignment: 'center',
                color: '#8a827a', margin: [0, 0, 0, 8] });
            }
            return;
          }

          // Titre H2/H3 dans le body (sous-section)
          if (tag === 'h2' || tag === 'h3') {
            const txt = node.textContent.replace(/✦/g, '').trim();
            if (txt) {
              content.push({ text: txt, font: titleFont,
                fontSize: tag === 'h2' ? fontSize + 3 : fontSize + 1,
                bold: true, alignment: isSubmit ? 'left' : 'center',
                margin: [0, 16, 0, 8] });
            }
            return;
          }

          // Paragraphe courant
          const inlines = domToInlines(node);
          const rawText = node.textContent || '';
          if (!rawText.trim()) return;

          const cs    = window.getComputedStyle(node);
          const align = isSubmit ? 'left'
                      : (cs.textAlign === 'center' ? 'center'
                       : cs.textAlign === 'right'  ? 'right'
                       : 'justify');

          // Indentation de premier paragraphe
          const indentPt = (!isSubmit && dims.ind && dims.ind !== '0' && dims.ind !== 'none')
            ? (parseFloat(dims.ind) || 0) * MM : 0;

          const pDef = {
            text: inlines.length === 1 && typeof inlines[0] === 'string' ? inlines[0] : inlines,
            font: isSubmit ? 'SourceSerif4' : bodyFont,
            fontSize: isSubmit ? 12 : fontSize,
            lineHeight: lineHeight,
            alignment: align,
            margin: [indentPt > 0 ? 0 : 0, 0, 0, isSubmit ? 6 : 2],
          };
          if (indentPt > 0 && !cl.contains('no-indent') && !cl.contains('scene-break')) {
            pDef.indent = indentPt;
          }
          content.push(pDef);
        });
      }
    });

    // Nettoyer les pageBreak orphelins en fin de contenu
    while (content.length && content[content.length-1].pageBreak) content.pop();

    // Garde : rien à exporter
    if (!content.length) {
      showToast('⚠ Aucun contenu à exporter.', 4000);
      return;
    }

    // ── 6. Définition du document pdfmake ──────────────────────────────────
    let pageNumOffset = folioStart - 1;

    const docDef = {
      pageSize:    { width: pageW, height: pageH },
      pageMargins: [mLeft, mTop, mRight, mBot],
      content,
      defaultStyle: {
        font:       isSubmit ? 'SourceSerif4' : bodyFont,
        fontSize:   isSubmit ? 12 : fontSize,
        lineHeight: lineHeight,
        color:      '#1a1714',
      },
      // En-tête courant (format édition seulement)
      header: (currentPage, pageCount, pageSize) => {
        if (!headerCourant || isSubmit || currentPage === 1) return null;
        return {
          text: headerCourant,
          font: headerFont,
          fontSize: 8,
          color: '#8a827a',
          alignment: 'center',
          margin: [mLeft, 10, mRight, 0],
        };
      },
      // Folio bas de page
      footer: (currentPage, pageCount) => {
        const hasTitlePage = !!(titre || auteur);
        const folioPage = currentPage - (hasTitlePage ? 1 : 0);
        if (hasTitlePage && currentPage === 1) return null;
        const folioNum = folioPage + pageNumOffset;
        return {
          text: String(folioNum),
          alignment: 'center',
          font: 'SourceSerif4',
          fontSize: 9,
          color: '#8a827a',
          margin: [mLeft, 0, mRight, 8],
        };
      },
      info: {
        title:  titre  || 'Atelier Édition',
        author: auteur || '',
      },
    };

    // ── 7. Résoudre les images base64 asynchrones ──────────────────────────
    const imagePromises = content
      .map((item, idx) => ({ item, idx }))
      .filter(({ item }) => item && item._imagePromise);

    if (imagePromises.length > 0) {
      const resolvedB64 = await Promise.all(imagePromises.map(({ item }) => item._imagePromise));

      [...imagePromises].reverse().forEach(({ item, idx }, ri) => {
        const i   = imagePromises.length - 1 - ri;
        const b64 = resolvedB64[i];

        if (!b64) {
          content[idx] = { text: '[image non disponible]', italics: true, color: '#8a827a' };
          return;
        }

        if (item._isFullPageImg) {
          // Élément ancre : force le saut de page et remplit la hauteur de page
          // pour que pdfmake ne colle pas le contenu suivant sur la même page.
          const anchor = {
            text: ' ',
            fontSize: 0.1,
            margin: [0, 0, 0, pageH - mTop - mBot],
            pageBreak: item._needsPageBreakBefore ? 'before' : undefined,
          };
          // Image positionnée exactement aux coordonnées calculées
          const imgNode = {
            image: b64,
            width:  item._targetWPt,
            height: item._targetHPt,
            absolutePosition: { x: item._xPos, y: item._yPos },
          };
          content.splice(idx, 1, anchor, imgNode);
        } else {
          // Image inline normale
          const imgNode = { image: b64, width: item.width,
            alignment: item.alignment, margin: item.margin };
          if (item._needsPageBreakBefore) imgNode.pageBreak = 'before';
          content[idx] = imgNode;
        }
      });
    }

    // ── 8. Générer et télécharger ───────────────────────────────────────────
    const filename = (titre ? titre.replace(/[^a-zA-Z0-9À-ÿ _-]/g, '').trim() : 'roman') + '.pdf';
    pdfMake.createPdf(docDef).download(filename, () => {
      showToast('✓ PDF téléchargé', 3000, 'ok');
    });

  } catch(err) {
    console.error('[printPDF pdfmake]', err);
    showToast('⚠ Erreur PDF : ' + (err.message || err), 6000);
  } finally {
    setExportBusy(false);
  }
}

// ── EXPORT WORD (.docx réel via docx.js) ───────────────
async function exportWord() {
  setExportBusy(true);
  try {
    await _exportWordCore();
  } finally {
    setExportBusy(false);
  }
}

async function _exportWordCore() {
  const raw = getDomVal('raw-input').trim();
  if (!raw) { showToast(_t('toast_no_export_text')); return; }
  if (!window.docx) { showToast(_t('toast_docx_lib_missing')); return; }

  showToast(_t('toast_generating_word'));

  const {
    Document, Packer, Paragraph, TextRun, ImageRun,
    AlignmentType, HeadingLevel, PageBreak, PageOrientation,
    Footer, PageNumber,
    convertMillimetersToTwip: mm2t,
  } = window.docx;

  // ── Paramètres actifs ──────────────────────────────────
  const fmt      = getDomVal('page-format');
  const isSubmit = isSubmitFormat(fmt);
  const fsRaw    = parseFloat(getDomVal('font-size'));
  const lhRaw    = parseFloat(getDomVal('line-height'));
  const indRaw   = getDomVal('indent-size');

  const fs  = isSubmit ? 12  : fsRaw;
  const lh  = isSubmit ? 2.0 : lhRaw;
  const bodyHp  = fs * 2;                   // demi-points
  const lineVal = Math.round(lh * 240);     // twips (240 = interligne simple)
  const txAlign = isSubmit ? AlignmentType.LEFT : AlignmentType.JUSTIFIED;

  // Indentation 1re ligne (em → mm → twips)
  let indTwip = 0;
  if (!isSubmit && indRaw && indRaw !== '0') {
    const indMm = indRaw.endsWith('em') ? parseFloat(indRaw) * fs * 0.353 : parseFloat(indRaw);
    if (!isNaN(indMm)) indTwip = mm2t(indMm);
  }

  // Dimensions page — lire depuis getPageDims() — source unique
  const PD = getPageDims();

  const zoneW = PD.pageW - PD.padLeft - PD.padRight;   // largeur zone texte en mm
  const zoneH = PD.pageH - PD.padTop  - PD.padBot;     // hauteur zone texte en mm

  // ── Helpers constructeurs ──────────────────────────────
  const sp0 = { before:0, after:0, line: lineVal, lineRule:'auto' };

  function run(text, opts = {}) {
    return new TextRun({ text, font:'Times New Roman', size: bodyHp, ...opts });
  }

  // Parsing inline *italique* **gras** _souligné_ pour Word (4.1)
  function parseInlineRuns(text) {
    const parts = text.split(/(\*\*[^*]+\*\*|\*[^*]+\*|_[^_]+_)/);
    return parts.flatMap(p => {
      if (!p) return [];
      if (p.startsWith('**') && p.endsWith('**'))
        return [new TextRun({ text: p.slice(2,-2), font:'Times New Roman', size:bodyHp, bold:true })];
      if (p.startsWith('*') && p.endsWith('*'))
        return [new TextRun({ text: p.slice(1,-1), font:'Times New Roman', size:bodyHp, italics:true })];
      if (p.startsWith('_') && p.endsWith('_'))
        return [new TextRun({ text: p.slice(1,-1), font:'Times New Roman', size:bodyHp, underline:{} })];
      return [new TextRun({ text: p, font:'Times New Roman', size:bodyHp })];
    });
  }

  function para(children, align, indent = {}, spacing = sp0, pageBreakBefore = false) {
    return new Paragraph({ children, alignment: align, spacing, indent,
                           pageBreakBefore });
  }

  function bodyPara(text, noInd = false) {
    return para(parseInlineRuns(text), txAlign,
                noInd ? {} : { firstLine: indTwip });
  }

  function sceneBreakPara() {
    return para([run('* * *')], AlignmentType.CENTER,
                {}, { before: mm2t(4), after: mm2t(4), line: lineVal, lineRule:'auto' });
  }

  // Chapitre H1 : saut de page avant + grand espace blanc (simule la zone déco)
  // On reproduit le 1/4 de page de blanc avec des paragraphes vides espacés
  function chapterParas(text) {
    const result = [];
    // Espace avant le titre (~1/4 page) via spacing before
    const spaceBefore = mm2t(Math.round(zoneH * 0.28));
    result.push(new Paragraph({
      children: [
        new TextRun({
          text: '✦ ',
          font: 'Arial Unicode MS',
          size: Math.round(bodyHp * 0.9),
          color: 'C8A84B',
        }),
        run(isSubmit ? text.toUpperCase() : text,
            { bold:true, size: isSubmit ? bodyHp : Math.round(bodyHp * 1.6) }),
      ],
      alignment: isSubmit ? AlignmentType.LEFT : AlignmentType.CENTER,
      spacing: { before: spaceBefore, after: mm2t(12), line: lineVal, lineRule:'auto' },
      pageBreakBefore: true,
    }));
    return result;
  }

  function sectionPara(text) {
    return para([run(text, { bold:true, size: Math.round(bodyHp * 1.1) })],
                isSubmit ? AlignmentType.LEFT : AlignmentType.CENTER,
                {},
                { before: mm2t(8), after: mm2t(4), line: lineVal, lineRule:'auto' });
  }

  // ── Helpers image ──────────────────────────────────────

  async function loadImage(src) {
    return new Promise((resolve, reject) => {
      const im = new Image();
      im.onload  = () => resolve(im);
      im.onerror = reject;
      im.src = src;
    });
  }

  function mimeOf(src) {
    return src.startsWith('data:image/png') ? 'png'
         : src.startsWith('data:image/gif') ? 'gif' : 'jpg';
  }

  /**
   * Rend une image sur canvas en appliquant rotation + mode (contain/cover).
   * Retourne { buf: ArrayBuffer, wpx, hpx, type } prêt pour ImageRun.
   *
   * targetWmm / targetHmm = dimensions cibles dans le document (mm)
   * On travaille à 300 dpi pour la qualité d'impression.
   * Si l'image source est plus grande, on garde sa résolution native.
   */
  const DPI = 300;
  const MM_TO_PX = DPI / 25.4;   // px par mm à 300 dpi

  function getRotatedBoundingBox(w, h, angleDeg) {
    const rad = angleDeg * Math.PI / 180;
    const cos = Math.abs(Math.cos(rad));
    const sin = Math.abs(Math.sin(rad));
    return {
      bbW: Math.round(w * cos + h * sin),
      bbH: Math.round(w * sin + h * cos),
    };
  }

  async function renderImgToCanvas(src, targetWmm, targetHmm, rotation, mode) {
    const im  = await loadImage(src);
    const rot = ((rotation || 0) % 360 + 360) % 360;

    // Pour tout angle (pas seulement 90°/270°), calculer le bounding box réel (2.4)
    const srcNatW = im.naturalWidth;
    const srcNatH = im.naturalHeight;
    const { bbW: srcLogW, bbH: srcLogH } = getRotatedBoundingBox(srcNatW, srcNatH, rot);

    // Dimensions cibles à 300 dpi
    const tWpx = Math.round(targetWmm * MM_TO_PX);
    const tHpx = Math.round(targetHmm * MM_TO_PX);

    // Facteur d'échelle selon le mode
    const scaleX = tWpx / srcLogW;
    const scaleY = tHpx / srcLogH;
    let scale;
    if      (mode === 'cover')   scale = Math.max(scaleX, scaleY);
    else /* contain */           scale = Math.min(scaleX, scaleY);

    // Dimensions de dessin de l'image ORIGINALE (avant rotation) sur le canvas
    const drawW = srcNatW * scale;
    const drawH = srcNatH * scale;

    const canvas = document.createElement('canvas');
    canvas.width  = tWpx;
    canvas.height = tHpx;
    const ctx = canvas.getContext('2d');

    // Fond blanc
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, tWpx, tHpx);

    ctx.save();
    ctx.translate(tWpx / 2, tHpx / 2);
    ctx.rotate(rot * Math.PI / 180);
    ctx.drawImage(im, -drawW / 2, -drawH / 2, drawW, drawH);
    ctx.restore();

    const dataURL = canvas.toDataURL('image/png');
    const b64 = dataURL.split(',')[1];
    const bin = atob(b64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);

    // wpx/hpx renvoyés = dimensions à 96 dpi pour docx.js
    const docWpx = Math.round(targetWmm * 96 / 25.4);
    const docHpx = Math.round(targetHmm * 96 / 25.4);

    return { buf: arr.buffer, wpx: docWpx, hpx: docHpx, type: 'png' };
  }

  /**
   * Construit un Paragraph ImageRun inline, rotation appliquée via canvas.
   */
  async function imagePara(imgDat, widthMm, align) {
    const rot    = ((imgDat.rotation || 0) % 360 + 360) % 360;
    const swap   = rot === 90 || rot === 270;
    const im2    = await loadImage(imgDat.src);
    const logW   = swap ? im2.naturalHeight : im2.naturalWidth;
    const logH   = swap ? im2.naturalWidth  : im2.naturalHeight;

    // Hauteur proportionnelle en mm
    const heightMm = widthMm * logH / logW;

    const { buf, wpx, hpx, type } = await renderImgToCanvas(
      imgDat.src, widthMm, heightMm, rot, 'contain'
    );

    return new Paragraph({
      children: [new ImageRun({ data: buf, transformation: { width: wpx, height: hpx }, type })],
      alignment: align,
      spacing: { before: mm2t(3), after: mm2t(3) },
    });
  }

  // ── Pied de page : numéro de page centré ──────────────
  const folioFontSize = isSubmit ? bodyHp : 18; // 9pt = 18 demi-points
  const folioFooter = new Footer({
    children: [
      new Paragraph({
        children: [
          new TextRun({
            children: [PageNumber.CURRENT],
            font: isSubmit ? 'Times New Roman' : 'Source Serif 4',
            size: folioFontSize,
            color: '555555',
          }),
        ],
        alignment: AlignmentType.CENTER,
        spacing: { before: 0, after: 0 },
      }),
    ],
  });

  // ── Sections docx ─────────────────────────────────────
  // docx.js modélise les sauts de page dédiés (image pleine page) via
  // des sections distinctes avec leurs propres marges — la même approche
  // que paginateNodes qui crée une .book-page dédiée.
  //
  // Structure : tableau de sections, chaque section = { props, children[] }
  // La section courante accumule les paragraphes ; une image fullpage
  // clôt la section courante et ouvre une section temporaire dédiée.

  function pageProps(w, h, mT, mB, mL, mR) {
    return {
      properties: {
        page: {
          size: { width: mm2t(w), height: mm2t(h), orientation: PageOrientation.PORTRAIT },
          margin: {
            top:    mm2t(mT),
            bottom: mm2t(mB),
            left:   mm2t(mL),
            right:  mm2t(mR),
            footer: mm2t(9),
          },
        },
      },
      footers: { default: folioFooter },
    };
  }

  const sections  = [];           // tableau final des sections
  let   current   = [];           // paragraphes de la section courante

  function flushSection(props = null) {
    if (current.length) {
      const base = props || pageProps(PD.w, PD.h, PD.mT, PD.mB, PD.mL, PD.mR);
      sections.push({ ...base, children: current });
      current = [];
    }
  }

  // ── Boucle principale ──────────────────────────────────
  const lines      = raw.split('\n');
  let prevEmpty    = false;
  let prevHead     = false;

  for (const line of lines) {
    const t = line.trim();

    if (!t) { prevEmpty = true; continue; }

    // ── Image ──────────────────────────────────────────
    const imgMatch = t.match(/^\[IMAGE:(.+?)\]$/i);
    if (imgMatch) {
      const key    = imgMatch[1].trim().toLowerCase();
      const imgDat = images[key];
      if (imgDat?.src?.startsWith('data:')) {
        try {
          const valign   = imgDat.valign || 'top';
          const isFullPg = valign === 'middle' || valign === 'fill';
          const alignDx  = imgDat.align === 'left'  ? AlignmentType.LEFT
                         : imgDat.align === 'right' ? AlignmentType.RIGHT
                         : AlignmentType.CENTER;

          if (isFullPg) {
            // ── Image pleine page : section dédiée ─────
            flushSection();
            const iMT = imgDat.marginTop  != null ? imgDat.marginTop  : PD.mT;
            const iMB = imgDat.marginBot  != null ? imgDat.marginBot  : PD.mB;
            const iML = imgDat.marginLeft != null ? imgDat.marginLeft : PD.mL;
            const iMR = imgDat.marginRight!= null ? imgDat.marginRight: PD.mR;
            const iZW = PD.w - iML - iMR;   // mm
            const iZH = PD.h - iMT - iMB;   // mm
            const pct = (imgDat.width || 100) / 100;
            const rot = ((imgDat.rotation || 0) % 360 + 360) % 360;

            // Dimensions cibles (en mm, renderImgToCanvas travaille à 300dpi en interne)
            let tWmm, tHmm, canvasMode;
            if (valign === 'fill') {
              tWmm = iZW; tHmm = iZH;
              canvasMode = 'cover';
            } else {
              const im2  = await loadImage(imgDat.src);
              const { bbW: logW, bbH: logH } = getRotatedBoundingBox(im2.naturalWidth, im2.naturalHeight, rot);
              tWmm = iZW * pct;
              tHmm = tWmm * logH / logW;
              if (tHmm > iZH) { tHmm = iZH; tWmm = tHmm * logW / logH; }
              canvasMode = 'contain';
            }

            const { buf, wpx: tWpx, hpx: tHpx, type } = await renderImgToCanvas(
              imgDat.src, tWmm, tHmm, rot, canvasMode
            );

            // Centrage vertical via spacing.before
            const vMarginMm = Math.max(0, (iZH - tHmm) / 2);
            const imgPg = new Paragraph({
              children: [new ImageRun({
                data: buf,
                transformation: { width: tWpx, height: tHpx },
                type,
              })],
              alignment: alignDx,
              spacing: { before: mm2t(vMarginMm), after: 0 },
            });

            const pgProps = pageProps(PD.w, PD.h, iMT, iMB, iML, iMR);
            sections.push({ ...pgProps, children: [imgPg] });
            // La section suivante repart à zéro (current est déjà vide)
          } else {
            // ── Image inline dans le flux ──────────────
            const wMm = zoneW * (imgDat.width || 100) / 100;
            current.push(await imagePara(imgDat, wMm, alignDx));
            if (imgDat.caption) {
              current.push(para([run(imgDat.caption, { italics:true, size: bodyHp - 2 })],
                                AlignmentType.CENTER));
            }
          }
        } catch(e) { /* image ignorée */ }
      }
      prevEmpty = false; prevHead = false;
      continue;
    }

    // ── Saut de scène ──────────────────────────────────
    if (isSceneBreak(t)) {
      current.push(sceneBreakPara());
      prevEmpty = true; prevHead = false;
      continue;
    }

    // ── Titres ────────────────────────────────────────
    const lv = detectHeadingLevel(t);

    if (lv === 1) {
      // H1 = nouveau chapitre → saut de page (pageBreakBefore dans chapterParas)
      chapterParas(t).forEach(p => current.push(p));
      prevHead = true; prevEmpty = false;
      continue;
    }

    if (lv === 2) {
      current.push(sectionPara(t));
      prevHead = true; prevEmpty = false;
      continue;
    }

    // ── Paragraphe normal ──────────────────────────────
    current.push(bodyPara(t, prevHead || prevEmpty));
    prevHead = false; prevEmpty = false;
  }

  // Flush dernière section
  flushSection();

  // Sécurité : si aucune section (texte vide après trim), créer une section vide
  if (!sections.length) {
    const base = pageProps(PD.w, PD.h, PD.mT, PD.mB, PD.mL, PD.mR);
    sections.push({ ...base, children: [new Paragraph({ children:[] })] });
  }

  // ── Création et téléchargement ─────────────────────
  const doc  = new Document({ sections });
  const blob = await Packer.toBlob(doc);
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href     = url;
  a.download = (currentProject || 'roman') + '.docx';
  a.click();
  URL.revokeObjectURL(url);
  showToast(_t('toast_word_done'));
}

// ── GESTION IMAGES — DÉLÉGATION GLOBALE ──────────────
// Les listeners sont sur document pour survivre aux cloneNode de paginateNodes.

document.addEventListener('click', (e) => {
  const imgWrap = e.target.closest('.book-image');
  // Désélectionner tout
  document.querySelectorAll('.book-image.img-selected').forEach(el => {
    el.classList.remove('img-selected');
    // Rétablir overflow:hidden sur les frames parentes
    const frame = el.closest('.frame-body, .frame-header');
    if (frame) frame.style.overflow = '';
  });
  if (imgWrap && imgWrap.dataset.imgKey) {
    e.stopPropagation();
    imgWrap.classList.add('img-selected');
    // Permettre aux poignées de déborder du frame
    const frame = imgWrap.closest('.frame-body, .frame-header');
    if (frame) frame.style.overflow = 'visible';
  }
});

document.addEventListener('mousedown', (e) => {
  const handle = e.target.closest('.img-resize-handle');
  if (!handle) return;
  e.preventDefault();
  e.stopPropagation();

  const wrap  = handle.closest('.book-image');
  if (!wrap) return;
  const key   = wrap.dataset.imgKey;
  if (!key || !images[key]) return;

  const side   = handle.dataset.side || 'right';
  const startX = e.clientX;
  const startW = images[key].width || 100;

  // Référence de largeur = le frame-body (vraie zone de texte)
  const frameEl = wrap.closest('.frame-body, .frame-header, .book-page');
  const refW    = frameEl ? frameEl.getBoundingClientRect().width : 400;

  const tooltip = wrap.querySelector('.img-size-tooltip');

  function onMove(mv) {
    const dx    = (mv.clientX - startX) * (side === 'left' ? -1 : 1);
    const delta = (dx / refW) * 100;
    const newW  = Math.min(200, Math.max(10, Math.round(startW + delta)));
    images[key].width = newW;
    // Mettre à jour TOUTES les instances de cette image dans le rendu
    document.querySelectorAll('.book-image[data-img-key="' + key + '"]').forEach(w => {
      w.style.width = newW + '%';
      const tip = w.querySelector('.img-size-tooltip');
      if (tip) tip.textContent = newW + '%';
    });
    // Sync sidebar
    const card = document.querySelector('[data-img="' + key + '"]');
    if (card) {
      const slider = card.querySelector('input[type=range]');
      if (slider) slider.value = Math.min(150, newW);
      const lbl = card.querySelector('.range-val');
      if (lbl) lbl.textContent = newW + '%';
    }
  }

  function onUp() {
    window.removeEventListener('mousemove', onMove);
    window.removeEventListener('mouseup', onUp);
    // Re-paginer seulement au relâchement
    formatRoman();
  }

  window.addEventListener('mousemove', onMove);
  window.addEventListener('mouseup', onUp);
});

